#include <iostream>
using namespace std;

int main() {
    int n;
    cin >> n;

    int binary[32] = {0};
    int index = 0;

    while (n > 0) {
        binary[index++] = n % 2;
        n /= 2;
    }

    for (int i = index - 1; i >= 0; i--) {
        cout << binary[i];
    }
    cout << endl;

    return 0;
}

#include <iostream>
using namespace std;

int main() {
    char a = 3;
    char b = -2;
    char c = a + b;

    cout << "a = " << (int)a << endl;
    cout << "b = " << (int)b << endl;
    cout << "a + b = " << (int)c << endl;

    // 显示二进制
    cout << "a的补码：";
    for (int i = 7; i >= 0; i--) {
        cout << ((a >> i) & 1);
    }
    cout << endl;

    return 0;
}

#include <iostream>
#include <string>
using namespace std;

int main() {
    string binary;
    cin >> binary;

    int decimal = 0;
    for (char c : binary) {
        decimal = decimal * 2 + (c - '0');
    }

    cout << decimal << endl;
    return 0;
}
